from sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelfrom typing import Optionalfrom sqlalchemy import TIMESTAMP,VARCHAR,BOOLEAN,INTEGER,UUIDimport uuid,datetimeclass PlatformUserModel(BaseModel):    __tablename__ = 'platform_user'    user_id: Mapped[uuid.UUID] = mapped_column(UUID, primary_key=True)    phone: Mapped[Optional[str]] = mapped_column(VARCHAR(20))    email: Mapped[Optional[str]] = mapped_column(VARCHAR(128))    password: Mapped[str] = mapped_column(VARCHAR(128), comment="""md5""")    role: Mapped[Optional[str]] = mapped_column(VARCHAR(16), comment="""founder investor fa expert corp gov""")    status: Mapped[str] = mapped_column(VARCHAR(16), comment="""active, suspended,deleted""")    is_verified: Mapped[bool] = mapped_column(BOOLEAN, comment="""0-不实名认证，1实名认证""")    lang_pref: Mapped[Optional[str]] = mapped_column(VARCHAR(4), comment="""zh,en""")    token_count: Mapped[int] = mapped_column(INTEGER, comment="""token数""")    last_active: Mapped[datetime.datetime] = mapped_column(TIMESTAMP, comment="""最后活跃时间""")    created_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)    updated_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)